"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[7033],{155961:a=>{a.exports=JSON.parse('{"tag":{"label":"race","permalink":"/dst-api-webdocs/docs/tags/race","allTagsPath":"/dst-api-webdocs/docs/tags","count":12,"items":[{"id":"game-scripts/prefabs/boatrace_checkpoint","title":"Boatrace Checkpoint","description":"Acts as a raceway checkpoint in the Boatrace event, detecting approaching beacons, dispensing flags, handling hammering interactions, and managing lighting and state transitions during races.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatrace_checkpoint"},{"id":"game-scripts/prefabs/boatrace_checkpoint_indicator","title":"Boatrace Checkpoint Indicator","description":"Acts as a visual marker that rotates to point toward the nearest race checkpoint during a boat race, and triggers music playback for nearby players.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatrace_checkpoint_indicator"},{"id":"game-scripts/brains/boatrace_primematebrain","title":"Boatrace Primematebrain","description":"Implements the AI behavior for the prime mate in boat races, prioritizing buoy tossing, leak repair, fire suppression, and rowing to keep the boat functional and competitive.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/boatrace_primematebrain"},{"id":"game-scripts/components/boatrace_proximitybeacon","title":"Boatrace Proximitybeacon","description":"Registers event callbacks for boat race start and finish events on an entity, enabling custom logic when a boat race begins or ends.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatrace_proximitybeacon"},{"id":"game-scripts/prefabs/boatrace_spectator_dragonling","title":"Boatrace Spectator Dragonling","description":"A flying companion entity that follows the race indicator during boat races, reacting to leaks and checkpoints in the environment.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatrace_spectator_dragonling"},{"id":"game-scripts/prefabs/boatrace_start","title":"Boatrace Start","description":"Acts as the starting beacon for the Year of the Dragon boat race event, managing race initialization, checkpoint coordination, beacon tracking, and prize distribution.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatrace_start"},{"id":"game-scripts/prefabs/carrat_ghostracer","title":"Carrat Ghostracer","description":"A non-player character prefab representing a Ghost Racer carrat that participates in the Year of the Crow (YOTC) race, with stat-based performance modifiers and dynamic behavior during races.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carrat_ghostracer"},{"id":"game-scripts/stategraphs/SGcarrat","title":"Sgcarrat","description":"Defines the state machine and behavior logic for carrat entities, including movement, burrowing, racing animations, and interaction with race-related components.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGcarrat"},{"id":"game-scripts/prefabs/yotc_carrat_scale","title":"Yotc Carrat Scale","description":"A gym-scale structure that accepts carrat rats, displays their stats via animated rods, and manages their interaction during training.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotc_carrat_scale"},{"id":"game-scripts/components/yotc_racecompetitor","title":"Yotc Racecompetitor","description":"Manages race participation logic for entities competing in YOTC-style races, including checkpoint navigation, stamina management, and race completion or abort handling.","permalink":"/dst-api-webdocs/docs/game-scripts/components/yotc_racecompetitor"},{"id":"game-scripts/components/yotc_racestart","title":"Yotc Racestart","description":"Manages race state transitions and callback hooks for a yotc race event on an entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/yotc_racestart"},{"id":"game-scripts/components/yotc_racestats","title":"Yotc Racestats","description":"Manages point-based racing statistics for entities, including stats modification, random point allocation, degradation, and baseline tracking.","permalink":"/dst-api-webdocs/docs/game-scripts/components/yotc_racestats"}],"unlisted":false}}')}}]);